// --- กำหนดค่าคงที่ ---
const diameter = 0.4;      // เส้นผ่านศูนย์กลางล้อ (เมตร)
const finalRatio = 2;    // อัตราทดเฟืองท้าย (เช่น 2:1)

// --- การคำนวณ ---
const engineRpm = msg.payload;         // รับค่า RPM ของเครื่องยนต์/มอเตอร์
const wheelRpm = engineRpm / finalRatio; // รอบหมุนที่ล้อจริง

// คำนวณความเร็ว (m/s)
const velocityMps = (wheelRpm * Math.PI * diameter) / 60;

// แปลงเป็น (km/h)
const velocityKph = velocityMps * 3.6;

// --- ส่งผลลัพธ์ออก (ปัดเศษทิ้งให้เหลือเลขจำนวนเต็ม) ---
msg.payload = Math.floor(velocityKph);

return msg;

// --- Configuration ---
const MAX_RPM = 5500; 

// 1. รับค่าดิบจาก Buffer/Payload
let raw = msg.payload;

// 2. คำนวณ RPM: (ค่าดิบ / 32767) * Max RPM
// คงค่าบวกลบไว้ตามที่ต้องการ
let rpmActual = (raw / 32767) * MAX_RPM;

// 3. ส่งค่ากลับในรูปแบบ Object (ปัดเศษเป็นจำนวนเต็ม)
msg.payload = Math.round(rpmActual);

return msg;

// --- ตั้งค่ากระแสสูงสุด (Peak Current) ของกล่อง Bamocar ---
// ตรวจสอบจาก Model กล่อง หรือค่า I-max ในโปรแกรม NDrive
const MAX_CURRENT_LIMIT = 212.1; 

// ดึงค่า raw data
let raw = msg.payload;

// 2. คำนวณเป็นหน่วย Amperes (Arms)
// สูตร: (ค่าดิบ / 32767) * ค่ากระแสสูงสุด
let realAmp = (raw / 32767) * MAX_CURRENT_LIMIT;

// 3. ส่งค่าออกไป (ปัดทศนิยม 1 ตำแหน่งเพื่อให้ดูสวยงาม)
msg.payload = parseFloat(realAmp.toFixed(1));

return msg;

// 1. แปลง msg.payload จาก String ให้เป็นตัวเลข (Number)
let raw = Number(msg.payload);


// จุดอ้างอิง
const x1 = 11446; // 25 C
const y1 = 30;
const x2 = 16000; // 60 C
const y2 = 100;

// 3. คำนวณ (ตอนนี้ raw เป็นตัวเลขแน่นอนแล้ว)
let celsius = y1 + (raw - x1) * (y2 - y1) / (x2 - x1);

// 4. ส่งออกค่าที่คำนวณได้
msg.payload = Number(celsius.toFixed(2));
return msg;

// แยกข้อความด้วยคอมมา
var d = msg.payload.split(",");

// สร้าง Object ใหม่ (เรียงตามลำดับใน ESP32)
msg.payload = {
    "rpm": parseInt(d[0]),
    "amp": parseFloat(d[1]),
    "volt": parseFloat(d[2]),
    "trq": parseInt(d[3]),
    "mode": d[4],
