// 1. ดึงข้อมูล Object จากโหนดก่อนหน้า
var d = msg.payload;

// 2. สร้าง Timestamp (เวลาปัจจุบันของเครื่อง)
// แบบ ISO: 2026-04-05T23:15:00.123Z (ละเอียดถึงมิลลิวินาที อ่านง่ายใน Excel)
var timestamp = new Date().toISOString();

// 3. เอา Timestamp มาวางไว้เป็น Column แรกสุด
var csvRow = [
    timestamp,     
    d.rpm,
    d.amp,
    d.volt,
    d.trq,
    d.mode,
    d.igbtC,
    d.motC,
    d.err,
    d.warn,
    d.L_REGEN,
    d.L_ERR,
    d.L_WARN,
    d.L_OK,
    d.L_PUMP,
